const CONFIG = {
 XP_MAX: 200,
 MOBILE_BREAKPOINT: 600,
 PARALLAX_SPEED: 0.3,
 CURSOR_RING_EASING: 0.12,
 STAGGER_DELAY_MS: 80,
 NAVBAR_SCROLL_THRESHOLD: 60,
 TOAST_DELAY_DESKTOP: 3000,
 TOAST_DELAY_MOBILE: 2000,
 WELCOME_XP_DELAY: 2000,
 HUD_MINIMIZE_DELAY: 3500,
};
const App = {
 name: 'CEEVS Web',
 version: '2.0.0',
 modules: [],
 isInitialized: false,
 register(module) {
 if (module && module.name && module.init) {
 this.modules.push(module);
 }
 },
 init() {
 if (this.isInitialized) return;
 console.log(`🚀 Inicializando ${this.name} v${this.version}`);
 if (document.readyState === 'loading') {
 document.addEventListener('DOMContentLoaded', () => this._initModules());
 } else {
 this._initModules();
 }
 this.isInitialized = true;
 },
 _initModules() {
 for (const module of this.modules) {
 try {
 module.init();
 console.log(`✓ ${module.name} inicializado`);
 } catch (error) {
 console.error(`✗ Error inicializando ${module.name}:`, error);
 }
 }
 },
 unregister(moduleName) {
 this.modules = this.modules.filter(m => m.name !== moduleName);
 },
 getModule(moduleName) {
 return this.modules.find(m => m.name === moduleName);
 },
};
if (document.readyState !== 'loading') {
 App.init();
}
const DOM = {
 select(selector) {
 return document.querySelector(selector);
 },
 selectAll(selector) {
 return document.querySelectorAll(selector);
 },
 byId(id) {
 return document.getElementById(id);
 },
 addClass(el, className) {
 if (el) el.classList.add(className);
 },
 removeClass(el, className) {
 if (el) el.classList.remove(className);
 },
 toggleClass(el, className) {
 if (el) el.classList.toggle(className);
 },
 hasClass(el, className) {
 return el ? el.classList.contains(className) : false;
 },
 attr(el, attr, value) {
 if (el) el.setAttribute(attr, value);
 },
 getAttr(el, attr) {
 return el ? el.getAttribute(attr) : null;
 },
 html(el, html) {
 if (el) el.innerHTML = html;
 },
 getHtml(el) {
 return el ? el.innerHTML : '';
 },
 text(el, text) {
 if (el) el.textContent = text;
 },
 getText(el) {
 return el ? el.textContent : '';
 },
 on(el, event, handler) {
 if (el) el.addEventListener(event, handler);
 },
 off(el, event, handler) {
 if (el) el.removeEventListener(event, handler);
 },
 delegate(parent, selector, event, handler) {
 if (!parent) return;
 parent.addEventListener(event, (e) => {
 if (e.target.matches(selector)) handler(e);
 });
 },
 hide(el) {
 if (el) el.style.display = 'none';
 },
 show(el, display = 'block') {
 if (el) el.style.display = display;
 },
 toggle(el) {
 if (el) el.style.display = el.style.display === 'none' ? 'block' : 'none';
 },
 getStyle(el, prop) {
 return el ? window.getComputedStyle(el).getPropertyValue(prop) : null;
 },
 setStyles(el, styles) {
 if (!el) return;
 for (const [prop, value] of Object.entries(styles)) {
 el.style[prop] = value;
 }
 },
 getRect(el) {
 return el ? el.getBoundingClientRect() : null;
 },
 isInViewport(el) {
 if (!el) return false;
 const rect = el.getBoundingClientRect();
 return (
 rect.top >= 0 &&
 rect.left >= 0 &&
 rect.bottom <= (window.innerHeight || document.documentElement.clientHeight) &&
 rect.right <= (window.innerWidth || document.documentElement.clientWidth)
 );
 },
 click(el) {
 if (el) el.click();
 },
 focus(el) {
 if (el) el.focus();
 },
 blur(el) {
 if (el) el.blur();
 },
};
const Storage = {
 prefix: 'ceevs_',
 set(key, value) {
 try {
 const fullKey = this.prefix + key;
 const serialized = JSON.stringify(value);
 localStorage.setItem(fullKey, serialized);
 return true;
 } catch (error) {
 console.error('Error saving to localStorage:', error);
 return false;
 }
 },
 get(key, defaultValue = null) {
 try {
 const fullKey = this.prefix + key;
 const value = localStorage.getItem(fullKey);
 return value ? JSON.parse(value) : defaultValue;
 } catch (error) {
 console.error('Error reading from localStorage:', error);
 return defaultValue;
 }
 },
 remove(key) {
 try {
 const fullKey = this.prefix + key;
 localStorage.removeItem(fullKey);
 return true;
 } catch (error) {
 console.error('Error removing from localStorage:', error);
 return false;
 }
 },
 clear() {
 try {
 const keys = Object.keys(localStorage);
 keys.forEach(key => {
 if (key.startsWith(this.prefix)) {
 localStorage.removeItem(key);
 }
 });
 return true;
 } catch (error) {
 console.error('Error clearing localStorage:', error);
 return false;
 }
 },
 keys() {
 const keys = Object.keys(localStorage);
 return keys.filter(key => key.startsWith(this.prefix))
 .map(key => key.replace(this.prefix, ''));
 },
 getSize() {
 let size = 0;
 const keys = Object.keys(localStorage);
 keys.forEach(key => {
 if (key.startsWith(this.prefix)) {
 const value = localStorage.getItem(key);
 size += key.length + (value ? value.length : 0);
 }
 });
 return size;
 },
};
'use strict';
const Gamification = {
 name: 'Gamification',
 xp: 0,
 earnedBadges: new Set(),
 sectionEarned: new Set(),
 hudMinimized: false,
 init() {
 this.xp = parseInt(localStorage.getItem('ceevs_xp') || '0');
 this.earnedBadges = new Set(JSON.parse(localStorage.getItem('ceevs_badges') || '[]'));
 this.sectionEarned = new Set(JSON.parse(localStorage.getItem('ceevs_sections') || '[]'));
 this._bindButtons();
 this._observeSections();
 this.updateHUD();
 this._welcomeXP();
 this._autoMinimizeMobile();
 },
 saveState() {
 localStorage.setItem('ceevs_xp', this.xp);
 localStorage.setItem('ceevs_badges', JSON.stringify([...this.earnedBadges]));
 localStorage.setItem('ceevs_sections', JSON.stringify([...this.sectionEarned]));
 },
 addXP(pts, icon, title, desc) {
 this.xp += pts;
 if (this.xp > CONFIG.XP_MAX) this.xp = CONFIG.XP_MAX;
 this.updateHUD();
 this.showToast(icon, title, desc || `+${pts} XP`);
 this.saveState();
 },
 updateHUD() {
 const pct = Math.min((this.xp / CONFIG.XP_MAX) * 100, 100);
 const fill = document.getElementById('hud-fill');
 const score = document.getElementById('hud-score');
 const scoreMin = document.getElementById('hud-score-min');
 const ptsLabel = document.getElementById('hud-pts-label');
 const ptsMax = document.getElementById('hud-pts-max');
 if (fill) fill.style.width = pct + '%';
 if (score) score.textContent = this.xp;
 if (scoreMin) scoreMin.textContent = this.xp + ' XP';
 const lvl = this.xp < 30 ? 'Explorador'
 : this.xp < 80 ? 'Conocedor'
 : this.xp < 150 ? 'Fan de CEEVS'
 : '⭐ Familia Virginia Sapp';
 if (ptsLabel) ptsLabel.textContent = this.xp + ' pts · ' + lvl;
 if (ptsMax) ptsMax.textContent = CONFIG.XP_MAX + ' pts';
 this.earnedBadges.forEach(id => {
 const b = document.querySelector(`[data-id="${id}"]`);
 if (b) b.classList.add('earned');
 });
 },
 unlockBadge(id) {
 if (this.earnedBadges.has(id)) return;
 this.earnedBadges.add(id);
 const b = document.querySelector(`[data-id="${id}"]`);
 if (b) {
 b.classList.add('earned');
 b.style.transform = 'scale(1.3)';
 setTimeout(() => b.style.transform = '', 300);
 }
 this.saveState();
 },
 showToast(icon, title, desc) {
 const t = document.getElementById('toast');
 if (!t) return;
 const iconEl = document.getElementById('toast-icon');
 const titleEl = document.getElementById('toast-title');
 const descEl = document.getElementById('toast-desc');
 if (iconEl) iconEl.textContent = icon;
 if (titleEl) titleEl.textContent = title;
 if (descEl) descEl.textContent = desc;
 clearTimeout(t._timer);
 t._dismissed = false;
 t.style.transition = 'transform .35s cubic-bezier(.34,1.56,.64,1)';
 t.style.opacity = '';
 t.classList.add('show');
 const delay = window.innerWidth <= 900 ? CONFIG.TOAST_DELAY_MOBILE : CONFIG.TOAST_DELAY_DESKTOP;
 t._timer = setTimeout(() => { if (!t._dismissed) t.classList.remove('show'); }, delay);
 },
 dismissToast(e) {
 if (e) e.stopPropagation();
 const t = document.getElementById('toast');
 if (!t || !t.classList.contains('show')) return;
 t._dismissed = true;
 clearTimeout(t._timer);
 const r = t.getBoundingClientRect();
 const cx = r.left + r.width / 2;
 const cy = r.top + r.height / 2;
 for (let i = 0; i < 16; i++) {
 const p = document.createElement('div');
 p.className = 'c-particle';
 const size = 3 + Math.random() * 5;
 const angle = (Math.PI * 2 / 16) * i + Math.random() * 0.4;
 const dist = 40 + Math.random() * 100;
 const tx = Math.cos(angle) * dist;
 const ty = Math.sin(angle) * dist;
 p.style.cssText = `position:fixed;width:${size}px;height:${size}px;left:${cx}px;top:${cy}px;--tx:${tx}px;--ty:${ty}px;opacity:${0.5 + Math.random() * 0.5};animation-duration:${0.4 + Math.random() * 0.4}s;`;
 document.body.appendChild(p);
 setTimeout(() => p.remove(), 900);
 }
 t.style.transition = 'transform .2s ease-in, opacity .15s';
 t.style.opacity = '0';
 setTimeout(() => {
 t.classList.remove('show');
 t.style.transition = '';
 t.style.opacity = '';
 }, 200);
 },
 toggleHUD() {
 this.hudMinimized = !this.hudMinimized;
 const main = document.getElementById('hud-main-content');
 const min = document.getElementById('hud-min-content');
 const toggle = document.getElementById('hud-toggle');
 if (main) main.style.display = this.hudMinimized ? 'none' : 'block';
 if (min) min.style.display = this.hudMinimized ? 'block' : 'none';
 if (toggle) toggle.textContent = this.hudMinimized ? '+' : '−';
 },
 _bindButtons() {
 const hudToggleBtn = document.getElementById('hud-toggle');
 if (hudToggleBtn) hudToggleBtn.addEventListener('click', () => this.toggleHUD());
 const toastEl = document.getElementById('toast');
 if (toastEl) toastEl.addEventListener('click', e => this.dismissToast(e));
 },
 _observeSections() {
 const sectionXP = {
 historia: 10, filosofia: 5, 'declaracion-fe': 5,
 niveles: 8, valores: 5, 'perfil-egresado': 5,
 quiz: 0, admisiones: 10, 'portal-educativo': 3,
 galeria: 5, testimonios: 5, exalumnos: 3, contacto: 8,
 };
 const sectionBadge = {
 historia: 'history', filosofia: 'explorer', niveles: 'explorer',
 valores: 'explorer', 'perfil-egresado': 'knower', contacto: 'contact',
 };
 const sectionMessages = {
 historia: ['📖', '¡Conociste nuestra historia!', '+10 XP · Conocedor de CEEVS'],
 niveles: ['🎒', '¡Exploraste los niveles!', '+8 XP · Sigue explorando'],
 admisiones: ['🎓', '¡Revisaste admisiones!', '+10 XP · ¡Casi listo para inscribirte!'],
 galeria: ['📸', '¡Viste la galería!', '+5 XP · La vida escolar en CEEVS'],
 testimonios: ['❤️', '¡Leíste testimonios!', '+5 XP · Familias felices'],
 contacto: ['🏫', '¡Llegaste al contacto!', '+8 XP · ¡Un paso más!'],
 valores: ['✦', '¡Conociste nuestros valores!', '+5 XP'],
 filosofia: ['📖', '¡Exploraste nuestra filosofía!', '+5 XP · Fundamentos de CEEVS'],
 'declaracion-fe': ['✝️', '¡Conociste nuestra fe!', '+5 XP · Identidad cristiana'],
 'perfil-egresado': ['🎓', '¡Viste el perfil del egresado!', '+5 XP'],
 'portal-educativo': ['🖥️', '¡Revisaste el portal!', '+3 XP'],
 exalumnos: ['🏫', '¡Comunidad de egresados!', '+3 XP'],
 };
 const obs = new IntersectionObserver(entries => {
 entries.forEach(e => {
 const id = e.target.id;
 if (e.isIntersecting && sectionXP[id] && !this.sectionEarned.has(id)) {
 this.sectionEarned.add(id);
 const pts = sectionXP[id];
 const m = sectionMessages[id] || ['✦', '¡Nuevo logro!', `+${pts} XP`];
 this.addXP(pts, m[0], m[1], m[2]);
 if (sectionBadge[id]) this.unlockBadge(sectionBadge[id]);
 }
 });
 }, { threshold: 0.3 });
 Object.keys(sectionXP).forEach(id => {
 const el = document.getElementById(id);
 if (el) obs.observe(el);
 });
 },
 _welcomeXP() {
 if (!localStorage.getItem('ceevs_welcomed')) {
 setTimeout(() => {
 this.addXP(5, '👋', '¡Bienvenido/a a CEEVS!', 'Comenzaste a explorar +5 XP');
 this.unlockBadge('explorer');
 localStorage.setItem('ceevs_welcomed', '1');
 }, CONFIG.WELCOME_XP_DELAY);
 }
 },
 _autoMinimizeMobile() {
 if (window.innerWidth <= CONFIG.MOBILE_BREAKPOINT) {
 setTimeout(() => {
 const main = document.getElementById('hud-main-content');
 const min = document.getElementById('hud-min-content');
 const toggle = document.getElementById('hud-toggle');
 if (main) main.style.display = 'none';
 if (min) min.style.display = 'block';
 if (toggle) toggle.textContent = '+';
 this.hudMinimized = true;
 }, CONFIG.HUD_MINIMIZE_DELAY);
 }
 },
};
function addXP(pts, icon, title, desc) { Gamification.addXP(pts, icon, title, desc); }
function unlockBadge(id) { Gamification.unlockBadge(id); }
App.register(Gamification);
'use strict';
const Main = {
 name: 'Main',
 init() {
 this._setupCursor();
 this._setupParallaxAndNavbar();
 this._setupMobileMenu();
 this._setupFAQ();
 this._setupCounters();
 this._setupScrollReveal();
 this._setupStagger();
 this._setupDropdowns();
 this._setupValorCards();
 this._setupContactForm();
 this._setupXPLinks();
 },
 _setupCursor() {
 const isTouch = ('ontouchstart' in window) || navigator.maxTouchPoints > 0;
 const cursor = document.getElementById('cursor');
 const cursorRing = document.getElementById('cursor-ring');
 if (!isTouch && cursor && cursorRing) {
 let mouseX = 0, mouseY = 0, ringX = 0, ringY = 0;
 document.addEventListener('mousemove', e => {
 mouseX = e.clientX;
 mouseY = e.clientY;
 cursor.style.left = mouseX + 'px';
 cursor.style.top = mouseY + 'px';
 });
 const animateRing = () => {
 ringX += (mouseX - ringX) * CONFIG.CURSOR_RING_EASING;
 ringY += (mouseY - ringY) * CONFIG.CURSOR_RING_EASING;
 cursorRing.style.left = ringX + 'px';
 cursorRing.style.top = ringY + 'px';
 requestAnimationFrame(animateRing);
 };
 animateRing();
 document.querySelectorAll('a,button,.valor-card,.nivel-card,.quiz-opt').forEach(el => {
 el.addEventListener('mouseenter', () => {
 cursor.style.transform = 'translate(-50%,-50%) scale(2.5)';
 cursorRing.style.opacity = '.2';
 });
 el.addEventListener('mouseleave', () => {
 cursor.style.transform = 'translate(-50%,-50%) scale(1)';
 cursorRing.style.opacity = '.5';
 });
 });
 } else if (cursor && cursorRing) {
 cursor.style.display = 'none';
 cursorRing.style.display = 'none';
 document.body.style.cursor = 'auto';
 }
 },
 _setupParallaxAndNavbar() {
 const isTouch = ('ontouchstart' in window) || navigator.maxTouchPoints > 0;
 const heroBg = document.getElementById('hero-parallax');
 let ticking = false;
 window.addEventListener('scroll', () => {
 const y = window.scrollY;
 const navbar = document.getElementById('navbar');
 if (navbar) navbar.classList.toggle('scrolled', y > CONFIG.NAVBAR_SCROLL_THRESHOLD);
 if (!isTouch && heroBg && !ticking) {
 ticking = true;
 requestAnimationFrame(() => {
 heroBg.style.transform = `translateY(${y * CONFIG.PARALLAX_SPEED}px)`;
 ticking = false;
 });
 }
 });
 },
 _setupMobileMenu() {
 const toggle = () => {
 const menu = document.getElementById('mobile-menu');
 const btn = document.getElementById('nav-hamburger');
 if (!menu || !btn) return;
 const open = menu.classList.toggle('open');
 btn.classList.toggle('open', open);
 document.body.style.overflow = open ? 'hidden' : '';
 };
 const hamburger = document.getElementById('nav-hamburger');
 if (hamburger) hamburger.addEventListener('click', toggle);
 const mmClose = document.querySelector('.mm-close');
 if (mmClose) mmClose.addEventListener('click', toggle);
 const mobileMenu = document.getElementById('mobile-menu');
 if (mobileMenu) {
 mobileMenu.addEventListener('click', e => {
 if (e.target === mobileMenu || e.target.tagName === 'A') toggle();
 });
 }
 this._toggleMobileMenu = toggle;
 },
 _setupFAQ() {
 document.addEventListener('click', e => {
 const btn = e.target.closest('.faq-q');
 if (!btn) return;
 const item = btn.closest('.faq-item');
 const isOpen = item.classList.contains('open');
 document.querySelectorAll('.faq-item.open').forEach(el => {
 el.classList.remove('open');
 el.querySelector('.faq-q').setAttribute('aria-expanded', 'false');
 });
 if (!isOpen) {
 item.classList.add('open');
 btn.setAttribute('aria-expanded', 'true');
 }
 });
 },
 _setupCounters() {
 const animateCount = el => {
 const target = parseInt(el.dataset.target);
 const duration = target > 1000 ? 2000 : 1200;
 const start = Date.now();
 const step = () => {
 const elapsed = Date.now() - start;
 const progress = Math.min(elapsed / duration, 1);
 const ease = 1 - Math.pow(1 - progress, 3);
 el.textContent = Math.round(ease * target).toLocaleString();
 if (progress < 1) requestAnimationFrame(step);
 };
 step();
 };
 const obs = new IntersectionObserver(entries => {
 entries.forEach(e => {
 if (e.isIntersecting) { animateCount(e.target); obs.unobserve(e.target); }
 });
 }, { threshold: 0.5 });
 document.querySelectorAll('.count').forEach(el => obs.observe(el));
 },
 _setupScrollReveal() {
 const obs = new IntersectionObserver(entries => {
 entries.forEach(e => {
 if (e.isIntersecting) {
 setTimeout(() => e.target.classList.add('visible'), 60);
 obs.unobserve(e.target);
 }
 });
 }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });
 document.querySelectorAll('.reveal,.reveal-left,.reveal-right').forEach(el => obs.observe(el));
 },
 _setupStagger() {
 document.querySelectorAll(
 '.steps-row .step-box,' +
 '.testimonios-grid .testi-card,' +
 '.galeria-mosaic .gi,' +
 '.valores-grid .valor-card,' +
 '.niveles-cards .nivel-card'
 ).forEach((el, i) => {
 el.style.transitionDelay = (i * CONFIG.STAGGER_DELAY_MS) + 'ms';
 });
 },
 _setupDropdowns() {
 document.querySelectorAll('.nav-dropdown').forEach(dropdown => {
 let timeout;
 dropdown.addEventListener('mouseenter', () => {
 clearTimeout(timeout);
 dropdown.classList.add('dropdown-open');
 });
 dropdown.addEventListener('mouseleave', () => {
 timeout = setTimeout(() => dropdown.classList.remove('dropdown-open'), 200);
 });
 });
 },
 _setupValorCards() {
 let valorCount = 0;
 document.addEventListener('click', e => {
 const card = e.target.closest('.valor-card');
 if (!card) return;
 const wasActive = card.classList.contains('active');
 card.classList.toggle('active');
 if (!wasActive) {
 valorCount++;
 const badgeId = card.dataset.badge;
 if (valorCount === 1) addXP(5, '✦', '¡Explorando valores!', 'Conociste el primer valor +5 XP');
 if (valorCount === 5) { addXP(10, '🌟', '¡Medio camino!', 'Exploraste 5 valores +10 XP'); unlockBadge('knower'); }
 if (valorCount === 10) { addXP(15, '💎', '¡Conoces todos los valores!', '¡Explorador completo! +15 XP'); }
 if (badgeId) unlockBadge(badgeId);
 }
 });
 },
 _setupContactForm() {
 const btn = document.getElementById('f-submit-btn');
 if (!btn) return;
 btn.addEventListener('click', () => {
 const textEl = btn.querySelector('.f-submit-text');
 const spinnerEl = btn.querySelector('.f-submit-spinner');
 btn.disabled = true;
 if (textEl) textEl.style.display = 'none';
 if (spinnerEl) spinnerEl.style.display = 'inline-flex';
 addXP(25, '🏫', '¡Bienvenido/a a la familia CEEVS!', 'Solicitud enviada · +25 XP');
 unlockBadge('contact');
 setTimeout(() => {
 if (spinnerEl) spinnerEl.style.display = 'none';
 if (textEl) { textEl.textContent = '✓ ¡Solicitud enviada!'; textEl.style.display = ''; }
 btn.style.background = '#22c55e';
 btn.style.color = '#fff';
 setTimeout(() => {
 if (textEl) textEl.textContent = 'Enviar solicitud →';
 btn.style.background = '';
 btn.style.color = '';
 btn.disabled = false;
 }, 3500);
 }, 1500);
 });
 },
 _setupXPLinks() {
 const heroCta = document.querySelector('.hero-ctas .btn-cta-main[data-xp-action]');
 if (heroCta) {
 heroCta.addEventListener('click', () => {
 const pts = +heroCta.dataset.xpPts || 15;
 const icon = heroCta.dataset.xpIcon || '🎓';
 const title = heroCta.dataset.xpTitle || '¡Explorando admisiones!';
 const desc = heroCta.dataset.xpDesc || '+' + pts + ' XP';
 addXP(pts, icon, title, desc);
 });
 }
 document.addEventListener('click', e => {
 const el = e.target.closest('[data-xp-pts]');
 if (!el) return;
 const pts = +el.dataset.xpPts;
 const icon = el.dataset.xpIcon || '✦';
 const title = el.dataset.xpTitle || '¡Nuevo logro!';
 const desc = el.dataset.xpDesc || '+' + pts + ' XP';
 if (pts) addXP(pts, icon, title, desc);
 });
 },
};
function toggleMobileMenu() { Main._toggleMobileMenu && Main._toggleMobileMenu(); }
function submitForm() { document.getElementById('f-submit-btn')?.click(); }
function toggleFaq(btn) {
 const item = btn.closest('.faq-item');
 const isOpen = item.classList.contains('open');
 document.querySelectorAll('.faq-item.open').forEach(el => {
 el.classList.remove('open');
 el.querySelector('.faq-q').setAttribute('aria-expanded', 'false');
 });
 if (!isOpen) { item.classList.add('open'); btn.setAttribute('aria-expanded', 'true'); }
}
App.register(Main);
